Hi!

I'm new to exabgp and flowspec. I'm using a code from master branch.
I have a problem with receiving flow spec messages in json format. I'm using two exabgp instances.

First instance configuration:

```
process receive-flows {
    run ./syslog-1.py;
    encoder json;
}

template router {
    neighbor localhost {
        router-id 127.0.0.1;
        local-address 127.0.0.1;
        local-as 65000;
        peer-as 65000;
        group-updates false;
        hold-time 180;

        capability {
            graceful-restart 1200;
        }

        family {
            ipv4 unicast;
            ipv4 flow;
        }

        api {
            processes [ receive-flows ];
            receive {
                parsed;
                update;
            }
        }
    }
}

neighbor 192.168.56.1 {
    inherit localhost;
    description "ExaBGP-localhost";
}
