   at System.Security.Cryptography.RSA.SignData(Byte[] data, Int32 offset, Int32 count, HashAlgorithmName hashAlgorithm, RSASignaturePadding padding)
   at System.Security.Cryptography.RSA.SignData(Byte[] data, HashAlgorithmName hashAlgorithm, RSASignaturePadding padding)
   at Microsoft.IdentityModel.Tokens.AsymmetricSignatureProvider.Sign(Byte[] input)
   at System.IdentityModel.Tokens.Jwt.JwtSecurityTokenHandler.CreateEncodedSignature(String input, SigningCredentials signingCredentials)
   at System.IdentityModel.Tokens.Jwt.JwtSecurityTokenHandler.WriteToken(SecurityToken token)
   at APIGateway.Auth.JwtHandler.CreateUserToken(User user, List`1 roles) in /home/kaloyanmanev/Projects/edotailor/APIGateway/Auth/JwtHandler.cs:line 64
   at APIGateway.Services.UserService.AuthenticateUserAsync(String username, String password) in /home/kaloyanmanev/Projects/edotailor/APIGateway/Services/UserService.cs:line 27
